// activeChannelName resolves the display name for the switcher's collapsed
// mobile trigger. Falls back to the first channel, then empty.
func activeChannelName(channels []ChannelView, activeID string) string {
	for _, c := range channels {
		if c.ID == activeID {
			return c.Name
		}
	}
	if len(channels) > 0 {
		return channels[0].Name
	}
	return ""
}

