// mentionPalette is a small telegram-inspired set of distinct hues used
// to colour @mention rows. Indexed by hash(user_id) so the same user
// always lights up the same colour while two members named "John" get
// different ones.
var mentionPalette = []string{
	"#e57373", // red
	"#f06292", // pink
	"#ba68c8", // purple
	"#7986cb", // indigo
	"#64b5f6", // blue
	"#4db6ac", // teal
	"#81c784", // green
	"#ffb74d", // orange
	"#a1887f", // brown
}

func mentionColor(userID string) string {
	if userID == "" {
		return mentionPalette[0]
	}
	var h uint32 = 2166136261
	for i := 0; i < len(userID); i++ {
		h ^= uint32(userID[i])
		h *= 16777619
	}
	return mentionPalette[int(h)%len(mentionPalette)]
}

func mentionInitial(name string) string {
	for _, r := range name {
		return string(r)
	}
	return "?"
}

// bubbleColor picks the identity-dot colour for a member-style bubble. Real
// members key off the stable AuthorID; an as-human agent has no AuthorID, so it
// keys off the display name instead — giving the "citizen" a consistent colour
// like everyone else.
func bubbleColor(m MsgView) string {
	if m.AuthorID != "" {
		return mentionColor(m.AuthorID)
	}
	return mentionColor(m.AuthorName)
}

// MsgGroup is a run of consecutive same-author user messages rendered
// as a single visual bubble (telegram-style). System / thread-announce
// messages each live in their own one-element group so they keep their
// own styling.
type MsgGroup struct {
	AuthorID string
	Kind     MsgKind
	IsOwn    bool
	Messages []MsgView
}

// groupMessages run-length-encodes the asc-ordered message list by
// (AuthorID, Kind), but only collapses MsgKindUser runs — system and
// thread-announce kinds always stay in their own group so their
// non-bubble styling isn't smeared across neighbours.
func groupMessages(asc []MsgView, currentUserID string) []MsgGroup {
	out := make([]MsgGroup, 0, len(asc))
	for _, m := range asc {
		if len(out) > 0 {
			last := &out[len(out)-1]
			if last.Kind == MsgKindUser && m.Kind == MsgKindUser && last.AuthorID == m.AuthorID && last.AuthorID != "" {
				last.Messages = append(last.Messages, m)
				continue
			}
		}
		out = append(out, MsgGroup{
			AuthorID: m.AuthorID,
			Kind:     m.Kind,
			IsOwn:    m.Kind == MsgKindUser && currentUserID != "" && m.AuthorID == currentUserID,
			Messages: []MsgView{m},
		})
	}
	return out
}

func groupClass(g MsgGroup) string {
	cls := "bubble-group"
	switch g.Kind {
	case MsgKindSystem, MsgKindThreadAnnounce:
		cls += " system"
	default:
		if g.IsOwn {
			cls += " own"
		} else {
			cls += " other"
		}
	}
	return cls
}

