// chatChannelSignals builds the data-signals JSON that seeds the active
// channel + unread dots into the bag on page load. Merges over
// InitialSignals (which declares the keys empty).
func chatChannelSignals(d ChatPageData) string {
	var b strings.Builder
	b.WriteString(`{"active_channel":`)
	b.WriteString(strconv.Quote(d.ActiveID))
	b.WriteString(`,"active_channel_slug":`)
	b.WriteString(strconv.Quote(d.ActiveSlug))
	b.WriteString(`,"_translate_capable":`)
	if d.TranslateEnabled {
		b.WriteString("true")
	} else {
		b.WriteString("false")
	}
	b.WriteString(`,"chat_unread":{`)
	first := true
	for id, on := range d.Unread {
		if !on {
			continue
		}
		if !first {
			b.WriteByte(',')
		}
		b.WriteString(strconv.Quote(id))
		b.WriteString(":true")
		first = false
	}
	b.WriteString("}}")
	return b.String()
}

// reverseMessages flips the desc-from-DB slice so groupMessages walks
// oldest→newest. Returns a fresh slice — does not mutate the input.
func reverseMessages(msgs []MsgView) []MsgView {
	out := make([]MsgView, len(msgs))
	for i, m := range msgs {
		out[len(msgs)-1-i] = m
	}
	return out
}

