// attachGridClass picks a flexible grid sizing hint based on count.
// Phase 4 turns these into per-kind layout rules; Phase 2 just uses
// them to space chips reasonably.
func attachGridClass(n int) string {
	switch {
	case n == 1:
		return "msg-attach-grid-1"
	case n == 2:
		return "msg-attach-grid-2"
	default:
		return "msg-attach-grid-n"
	}
}

func attachIcon(kind string) string {
	switch kind {
	case "image":
		return "🖼"
	case "video":
		return "🎬"
	case "audio":
		return "🎵"
	case "pdf":
		return "📄"
	}
	return "📎"
}

// humanSize is a small kB / MB formatter for chip labels.
func humanSize(n int64) string {
	const (
		kib = 1024
		mib = 1024 * kib
	)
	switch {
	case n >= mib:
		return formatFloat(float64(n)/float64(mib), 1) + " MB"
	case n >= kib:
		return formatFloat(float64(n)/float64(kib), 0) + " KB"
	}
	return formatInt(n) + " B"
}

func formatInt(n int64) string {
	if n == 0 {
		return "0"
	}
	neg := n < 0
	if neg {
		n = -n
	}
	var b [20]byte
	i := len(b)
	for n > 0 {
		i--
		b[i] = byte('0' + n%10)
		n /= 10
	}
	if neg {
		i--
		b[i] = '-'
	}
	return string(b[i:])
}

func formatFloat(f float64, decimals int) string {
	if decimals == 0 {
		return formatInt(int64(f + 0.5))
	}
	mult := int64(1)
	for i := 0; i < decimals; i++ {
		mult *= 10
	}
	scaled := int64(f*float64(mult) + 0.5)
	whole := scaled / mult
	frac := scaled % mult
	// Pad frac with leading zeros to `decimals` width.
	fracStr := formatInt(frac)
	for len(fracStr) < decimals {
		fracStr = "0" + fracStr
	}
	return formatInt(whole) + "." + fracStr
}

